from __future__ import annotations

import pathlib
import sys
import time

from fastapi.testclient import TestClient

ROOT = pathlib.Path(__file__).resolve().parents[1]
if str(ROOT) not in sys.path:
    sys.path.insert(0, str(ROOT))

from backend.main import app


def assert_true(condition: bool, message: str) -> None:
    if not condition:
        raise AssertionError(message)


def post_json(client: TestClient, url: str, payload: dict) -> dict:
    resp = client.post(url, json=payload)
    assert_true(resp.status_code == 200, f"{url} failed: {resp.status_code} {resp.text}")
    return resp.json()


def get_json(client: TestClient, url: str) -> dict:
    resp = client.get(url)
    assert_true(resp.status_code == 200, f"{url} failed: {resp.status_code} {resp.text}")
    return resp.json()


def main() -> None:
    nonce = str(int(time.time() * 1000))[-8:]
    sid = f"replay-smoke-{nonce}"
    with TestClient(app) as client:
        post_json(client, "/api/session/init", {"sessionId": sid})

        add_task = post_json(client, "/api/turn", {"sessionId": sid, "intent": "add task ship replay path"})
        tr0 = add_task["execution"]["toolResults"][0]
        assert_true(add_task["execution"]["ok"], "add task should succeed")
        assert_true(tr0["policy"]["code"] == "ok", "add task policy should be ok")
        assert_true(tr0["diff"]["tasks"] == 1, "add task should increase tasks by 1")
        before_idem_snapshot = get_json(client, f"/api/session/{sid}")
        before_idem_tasks = list((before_idem_snapshot.get("memory", {}) or {}).get("tasks", []))
        idem_first = post_json(
            client,
            "/api/turn",
            {"sessionId": sid, "intent": "add task idempotent item", "idempotencyKey": "idem-add-1"},
        )
        assert_true(idem_first["execution"]["ok"], "idempotent add first call should succeed")
        idem_second = post_json(
            client,
            "/api/turn",
            {"sessionId": sid, "intent": "add task idempotent item", "idempotencyKey": "idem-add-1"},
        )
        assert_true(idem_second["execution"]["ok"], "idempotent add second call should reuse success")
        assert_true(bool((idem_second.get("idempotency") or {}).get("reused", False)), "second idempotent call should be reused")
        session_after_idem = get_json(client, f"/api/session/{sid}")
        after_idem_tasks = list((session_after_idem.get("memory", {}) or {}).get("tasks", []))
        assert_true(len(after_idem_tasks) == len(before_idem_tasks) + 1, "idempotency retry should apply mutation only once")
        assert_true(int(idem_second.get("revision", 0) or 0) == int(idem_first.get("revision", 0) or 0), "reused idempotent response should preserve revision")
        explain = post_json(client, "/api/turn", {"sessionId": sid, "intent": "explain intent add task replay explain"})
        explain_tr = explain["execution"]["toolResults"][0]
        assert_true(explain["execution"]["ok"], "explain intent should succeed")
        assert_true(any("class:" in str(line).lower() for line in explain_tr.get("previewLines", [])), "explain intent should include class line")
        assert_true(any("route:" in str(line).lower() for line in explain_tr.get("previewLines", [])), "explain intent should include route line")
        preview = post_json(client, "/api/turn", {"sessionId": sid, "intent": "preview intent reset memory"})
        preview_tr = preview["execution"]["toolResults"][0]
        assert_true(preview["execution"]["ok"], "preview intent should succeed")
        assert_true(any("writes:" in str(line).lower() for line in preview_tr.get("previewLines", [])), "preview intent should include write count")
        preview_endpoint = post_json(client, f"/api/session/{sid}/intent/preview", {"intent": "reset memory"})
        assert_true(preview_endpoint["ok"], "intent preview endpoint should succeed")
        assert_true(len(preview_endpoint.get("writes", [])) >= 1, "intent preview endpoint should include write evaluations")
        route_meta = (add_task.get("kernelTrace", {}) or {}).get("route", {})
        assert_true(bool(route_meta.get("intentClass")), "kernel trace route should include intentClass")
        assert_true(isinstance(route_meta.get("confidence"), (int, float)), "kernel trace route should include confidence")

        clarify = post_json(client, "/api/turn", {"sessionId": sid, "intent": "delete task"})
        assert_true(not clarify["execution"]["ok"], "incomplete command should require clarification")
        assert_true(bool((clarify.get("envelope", {}) or {}).get("clarification", {}).get("required", False)), "envelope should flag clarification required")
        clarify_route = (clarify.get("kernelTrace", {}) or {}).get("route", {})
        assert_true(str(clarify_route.get("reason", "")) == "clarification_gate", "clarification should force clarification_gate route")
        clarify_tool = clarify["execution"]["toolResults"][0]
        assert_true(clarify_tool.get("policy", {}).get("code") == "clarification_required", "clarification turn should be policy-coded")
        assert_true("missing" in str(clarify["execution"].get("message", "")).lower() or "incomplete" in str(clarify["execution"].get("message", "")).lower(), "clarification response should explain incomplete command")
        perf = (add_task.get("kernelTrace", {}).get("runtime", {}) or {}).get("performance", {})
        slo = (add_task.get("kernelTrace", {}).get("runtime", {}) or {}).get("slo", {})
        assert_true("totalMs" in perf and "budgetMs" in perf and "withinBudget" in perf, "kernel trace should include performance budget telemetry")
        assert_true(int(perf.get("totalMs", 0)) >= 0, "turn total latency should be non-negative")
        assert_true("breachStreak" in slo and "throttled" in slo and "lastTotalMs" in slo, "kernel trace should include slo telemetry")

        undo = post_json(client, "/api/turn", {"sessionId": sid, "intent": "undo last"})
        tr_undo = undo["execution"]["toolResults"][0]
        assert_true(undo["execution"]["ok"], "undo should succeed after a mutation")
        assert_true(tr_undo["policy"]["code"] == "ok", "undo policy should be ok")
        assert_true(tr_undo["diff"]["tasks"] <= 0, "undo should not increase task count")

        add_task = post_json(client, "/api/turn", {"sessionId": sid, "intent": "add task ship replay path"})
        tr0 = add_task["execution"]["toolResults"][0]
        assert_true(add_task["execution"]["ok"], "add task should succeed")
        assert_true(tr0["policy"]["code"] == "ok", "add task policy should be ok")
        assert_true(tr0["diff"]["tasks"] == 1, "add task should increase tasks by 1")

        stale_resp = client.post(
            "/api/turn",
            json={"sessionId": sid, "intent": "add task stale write", "baseRevision": 0},
        )
        assert_true(stale_resp.status_code == 409, "stale revision write should return 409")
        stale_detail = stale_resp.json().get("detail", {})
        assert_true(stale_detail.get("code") == "revision_conflict", "stale write should report revision_conflict")

        merge_resp = client.post(
            "/api/turn",
            json={"sessionId": sid, "intent": "add note merged write", "baseRevision": 0, "onConflict": "rebase_if_commutative"},
        )
        assert_true(merge_resp.status_code == 200, "commutative stale write should merge when requested")
        merge_payload = merge_resp.json()
        assert_true(bool(merge_payload.get("merge", {}).get("rebased")), "merge payload should mark rebased true")
        assert_true(merge_payload.get("merge", {}).get("fromRevision") == 0, "merge should preserve source revision metadata")

        list_files = post_json(client, "/api/turn", {"sessionId": sid, "intent": "list files ."})
        tr_files = list_files["execution"]["toolResults"][0]
        assert_true(list_files["execution"]["ok"], "list files should succeed")
        assert_true(tr_files["policy"]["code"] == "ok", "list files policy should be ok")
        assert_true(bool(tr_files.get("previewLines")), "list files should include preview lines")

        read_file = post_json(client, "/api/turn", {"sessionId": sid, "intent": "read file README.md"})
        tr_read = read_file["execution"]["toolResults"][0]
        assert_true(read_file["execution"]["ok"], "read file should succeed")
        assert_true(tr_read["policy"]["code"] == "ok", "read file policy should be ok")
        assert_true(any("Generative UI" in line for line in tr_read.get("previewLines", [])), "read file should preview README contents")

        blocked_url = post_json(client, "/api/turn", {"sessionId": sid, "intent": "fetch url http://localhost:8787"})
        tr_url = blocked_url["execution"]["toolResults"][0]
        assert_true(not blocked_url["execution"]["ok"], "localhost fetch should be blocked by policy")
        assert_true(tr_url["policy"]["code"] == "url_not_allowed", "localhost fetch should be denied with url_not_allowed")

        turn_audit = post_json(client, "/api/turn", {"sessionId": sid, "intent": "show audit"})
        tr_audit = turn_audit["execution"]["toolResults"][0]
        assert_true(turn_audit["execution"]["ok"], "turn audit command should succeed")
        assert_true(any(str(line).startswith("allowed:") for line in tr_audit.get("previewLines", [])), "turn audit should return summary lines")
        turn_audit_op = post_json(client, "/api/turn", {"sessionId": sid, "intent": "show audit op add_task"})
        assert_true(turn_audit_op["execution"]["ok"], "turn audit op filter command should succeed")
        turn_audit_policy = post_json(client, "/api/turn", {"sessionId": sid, "intent": "show audit policy ok"})
        assert_true(turn_audit_policy["execution"]["ok"], "turn audit policy filter command should succeed")
        turn_trace = post_json(client, "/api/turn", {"sessionId": sid, "intent": "show trace"})
        tr_trace = turn_trace["execution"]["toolResults"][0]
        assert_true(turn_trace["execution"]["ok"], "turn trace command should succeed")
        assert_true(any("|" in str(line) for line in tr_trace.get("previewLines", [])), "turn trace should return compact trace lines")
        turn_trace_export = post_json(client, "/api/turn", {"sessionId": sid, "intent": "export trace"})
        assert_true(turn_trace_export["execution"]["ok"], "trace export command should succeed")
        assert_true(any(str(line).strip().startswith("{") for line in turn_trace_export["execution"]["toolResults"][0].get("previewLines", [])), "trace export should preview ndjson-like lines")
        turn_trace_summary = post_json(client, "/api/turn", {"sessionId": sid, "intent": "show trace summary"})
        tr_trace_summary = turn_trace_summary["execution"]["toolResults"][0]
        assert_true(turn_trace_summary["execution"]["ok"], "trace summary command should succeed")
        assert_true(any("count:" in str(line).lower() for line in tr_trace_summary.get("previewLines", [])), "trace summary should include count line")
        turn_trace_class = post_json(client, "/api/turn", {"sessionId": sid, "intent": "show trace class mutate"})
        assert_true(turn_trace_class["execution"]["ok"], "trace class filter command should succeed")
        turn_trace_denied = post_json(client, "/api/turn", {"sessionId": sid, "intent": "show trace denied"})
        assert_true(turn_trace_denied["execution"]["ok"], "trace denied filter command should succeed")
        trace_endpoint = get_json(client, f"/api/session/{sid}/trace?limit=20")
        assert_true(trace_endpoint["ok"], "trace endpoint should be available")
        assert_true(int(trace_endpoint.get("count", 0)) >= 1, "trace endpoint should return entries")
        first_trace = (trace_endpoint.get("items") or [{}])[-1]
        assert_true("route" in first_trace and "execution" in first_trace and "performance" in first_trace, "trace entry should include route/execution/performance")
        trace_ndjson_resp = client.get(f"/api/session/{sid}/trace?format=ndjson&limit=5")
        assert_true(trace_ndjson_resp.status_code == 200, "trace ndjson export should succeed")
        trace_ndjson_lines = [line for line in trace_ndjson_resp.text.splitlines() if line.strip()]
        assert_true(len(trace_ndjson_lines) >= 1, "trace ndjson should contain entries")
        trace_endpoint_mutate = get_json(client, f"/api/session/{sid}/trace?limit=20&intent_class=mutate")
        assert_true(trace_endpoint_mutate["ok"], "trace endpoint class filter should succeed")
        trace_endpoint_clarify = get_json(client, f"/api/session/{sid}/trace?limit=20&route_reason=clarification_gate")
        assert_true(trace_endpoint_clarify["ok"], "trace endpoint reason filter should succeed")
        trace_summary_endpoint = get_json(client, f"/api/session/{sid}/trace/summary?limit=200")
        assert_true(trace_summary_endpoint["ok"], "trace summary endpoint should succeed")
        assert_true("summary" in trace_summary_endpoint and "count" in trace_summary_endpoint["summary"], "trace summary endpoint should return summary payload")

        turn_restore_preview = post_json(client, "/api/turn", {"sessionId": sid, "intent": "restore preview"})
        tr_restore_preview = turn_restore_preview["execution"]["toolResults"][0]
        assert_true(turn_restore_preview["execution"]["ok"], "restore preview command should succeed")
        assert_true(any("apply with" in str(line).lower() for line in tr_restore_preview.get("previewLines", [])), "restore preview should provide apply hint")

        restore_apply_blocked = post_json(client, "/api/turn", {"sessionId": sid, "intent": "restore apply"})
        tr_restore_apply_blocked = restore_apply_blocked["execution"]["toolResults"][0]
        assert_true(not restore_apply_blocked["execution"]["ok"], "restore apply should require confirmation")
        assert_true(tr_restore_apply_blocked["policy"]["code"] == "confirmation_required", "restore apply should be policy-gated")

        complete = post_json(client, "/api/turn", {"sessionId": sid, "intent": "complete task 1"})
        tr1 = complete["execution"]["toolResults"][0]
        assert_true(complete["execution"]["ok"], "complete task should succeed")
        assert_true(tr1["policy"]["code"] == "ok", "complete policy should be ok")

        add_note = post_json(client, "/api/turn", {"sessionId": sid, "intent": "add note relation target"})
        assert_true(add_note["execution"]["ok"], "add note should succeed")

        invalid_link = post_json(client, "/api/turn", {"sessionId": sid, "intent": "link task 1 depends_on note 1"})
        invalid_link_tr = invalid_link["execution"]["toolResults"][0]
        assert_true(not invalid_link["execution"]["ok"], "depends_on should reject non-task targets")
        assert_true("task -> task" in str(invalid_link_tr.get("message", "")).lower(), "invalid depends_on should explain task->task constraint")

        link = post_json(client, "/api/turn", {"sessionId": sid, "intent": "link task 1 references note 1"})
        tr_link = link["execution"]["toolResults"][0]
        assert_true(link["execution"]["ok"], "link command should succeed")
        assert_true(tr_link["policy"]["code"] == "ok", "link policy should be ok")
        assert_true(int(link["kernelTrace"]["graph"].get("relations", 0)) >= 1, "graph should include at least one relation after link")

        watch = post_json(client, "/api/turn", {"sessionId": sid, "intent": "watch task 1 every 10m"})
        tr_watch = watch["execution"]["toolResults"][0]
        assert_true(watch["execution"]["ok"], "watch command should succeed")
        assert_true(tr_watch["policy"]["code"] == "ok", "watch policy should be ok")
        assert_true(int((watch.get("kernelTrace", {}).get("runtime", {}) or {}).get("jobsActive", 0)) >= 1, "runtime should report active jobs")

        list_jobs = post_json(client, "/api/turn", {"sessionId": sid, "intent": "list jobs"})
        assert_true(list_jobs["execution"]["ok"], "list jobs should succeed")
        assert_true("Jobs:" in str(list_jobs["execution"]["message"]), "list jobs should return job summary")

        pause = post_json(client, "/api/turn", {"sessionId": sid, "intent": "pause job 1"})
        assert_true(pause["execution"]["ok"], "pause job should succeed")
        assert_true("Paused job" in str(pause["execution"]["message"]), "pause should acknowledge")

        resume = post_json(client, "/api/turn", {"sessionId": sid, "intent": "resume job 1"})
        assert_true(resume["execution"]["ok"], "resume job should succeed")
        assert_true("Resumed job" in str(resume["execution"]["message"]), "resume should acknowledge")

        remind = post_json(client, "/api/turn", {"sessionId": sid, "intent": "remind note replay reminder every 1m"})
        assert_true(remind["execution"]["ok"], "remind schedule should succeed")

        tick = post_json(client, f"/api/session/{sid}/jobs/tick?force=true", {})
        assert_true(tick["ok"], "forced tick should succeed")
        assert_true(bool(tick.get("ran")), "forced tick should run at least one job")

        query_refs = post_json(client, "/api/turn", {"sessionId": sid, "intent": "show references for note 1"})
        labels = [b.get("label", "") for b in query_refs.get("plan", {}).get("blocks", [])]
        assert_true("Relation Query" in labels, "relation query block should be present")

        blocked = post_json(client, "/api/turn", {"sessionId": sid, "intent": "reset memory"})
        tr2 = blocked["execution"]["toolResults"][0]
        assert_true(not blocked["execution"]["ok"], "reset memory should be blocked without confirmation")
        assert_true(tr2["policy"]["code"] == "confirmation_required", "reset should require confirmation")

        confirmed = post_json(client, "/api/turn", {"sessionId": sid, "intent": "confirm reset memory"})
        tr3 = confirmed["execution"]["toolResults"][0]
        assert_true(confirmed["execution"]["ok"], "confirmed reset should succeed")
        assert_true(tr3["policy"]["code"] == "ok", "confirmed reset policy should be ok")
        assert_true(tr3["diff"]["tasks"] <= 0, "confirmed reset should not increase tasks")

        session = get_json(client, f"/api/session/{sid}")
        assert_true("kernelTrace" in session["lastTurn"], "session lastTurn should include kernelTrace")
        assert_true("journalTail" in session["lastTurn"]["kernelTrace"], "kernelTrace should include journal tail")
        assert_true("memory" in session and "tasks" in session["memory"], "session should keep backward-compatible memory projection")

        graph = get_json(client, f"/api/session/{sid}/graph?limit=20")
        assert_true(graph["ok"], "graph endpoint should be available")
        assert_true("counts" in graph and "entities" in graph["counts"], "graph response should include counts")
        jobs = get_json(client, f"/api/session/{sid}/jobs?limit=500")
        assert_true(jobs["ok"], "jobs endpoint should be available")
        assert_true(int(jobs.get("count", 0)) >= 1, "jobs endpoint should include scheduled watch job")
        assert_true(any("lastResult" in item for item in jobs.get("items", [])), "jobs should include lastResult metadata")
        jobs_before_ids = {str(item.get("id", "")) for item in jobs.get("items", [])}

        cancel = post_json(client, "/api/turn", {"sessionId": sid, "intent": "cancel job 1"})
        assert_true(cancel["execution"]["ok"], "cancel job should succeed")
        canceled_message = str(cancel["execution"]["message"])
        canceled_match = canceled_message.split("Canceled job ", 1)
        canceled_id = canceled_match[1].strip() if len(canceled_match) > 1 else ""
        assert_true(bool(canceled_id), "cancel response should include canceled job id")
        jobs_after_cancel = get_json(client, f"/api/session/{sid}/jobs?limit=500")
        jobs_after_ids = {str(item.get("id", "")) for item in jobs_after_cancel.get("items", [])}
        assert_true(canceled_id in jobs_before_ids, "canceled job id should exist before cancel")
        assert_true(canceled_id not in jobs_after_ids, "canceled job id should be removed after cancel")

        sid_dlq = f"replay-dlq-{nonce}"
        post_json(client, "/api/session/init", {"sessionId": sid_dlq})
        schedule_probe = post_json(client, "/api/turn", {"sessionId": sid_dlq, "intent": "schedule failing probe every 1m"})
        assert_true(schedule_probe["execution"]["ok"], "failing probe schedule should succeed")
        for _ in range(3):
            tick_dlq = post_json(client, f"/api/session/{sid_dlq}/jobs/tick?force=true", {})
            assert_true(tick_dlq["ok"], "forced tick for dlq should succeed")
        dead_letters = get_json(client, f"/api/session/{sid_dlq}/dead-letters?limit=50")
        assert_true(dead_letters["ok"], "dead letters endpoint should succeed")
        assert_true(int(dead_letters.get("count", 0)) >= 1, "dead letters should capture repeated job failures")
        runtime_health = get_json(client, f"/api/session/{sid_dlq}/runtime/health")
        assert_true(runtime_health["ok"], "runtime health endpoint should succeed")
        assert_true("jobs" in runtime_health and "deadLetters" in runtime_health and "slo" in runtime_health, "runtime health should include core sections")
        runtime_profile = get_json(client, f"/api/session/{sid_dlq}/runtime/profile?limit=200")
        assert_true(runtime_profile["ok"], "runtime profile endpoint should succeed")
        assert_true("latencyMs" in runtime_profile and "outcomes" in runtime_profile, "runtime profile should include latency/outcome sections")
        diagnostics = get_json(client, f"/api/session/{sid_dlq}/diagnostics")
        assert_true(diagnostics["ok"], "diagnostics endpoint should succeed")
        assert_true("health" in diagnostics and "selfCheck" in diagnostics and "traceSummary" in diagnostics, "diagnostics should include health/self-check/trace summary")
        assert_true("presence" in diagnostics and "activeCount" in diagnostics["presence"], "diagnostics should include presence summary")
        continuity = get_json(client, f"/api/session/{sid_dlq}/continuity")
        assert_true(continuity["ok"], "continuity endpoint should succeed")
        assert_true("summary" in continuity and "handoffP95Ms" in continuity["summary"], "continuity endpoint should include summary metrics")
        assert_true("health" in continuity and "status" in continuity["health"], "continuity endpoint should include health status")
        continuity_health = get_json(client, f"/api/session/{sid_dlq}/continuity/health")
        assert_true(continuity_health["ok"], "continuity health endpoint should succeed")
        assert_true("health" in continuity_health and "score" in continuity_health["health"], "continuity health endpoint should include score")
        continuity_history = get_json(client, f"/api/session/{sid_dlq}/continuity/history?limit=20")
        assert_true(continuity_history["ok"], "continuity history endpoint should succeed")
        assert_true("items" in continuity_history, "continuity history endpoint should return items")
        continuity_anomalies = get_json(client, f"/api/session/{sid_dlq}/continuity/anomalies?limit=20")
        assert_true(continuity_anomalies["ok"], "continuity anomalies endpoint should succeed")
        assert_true("items" in continuity_anomalies and "summary" in continuity_anomalies, "continuity anomalies endpoint should return items and summary")
        continuity_incidents = get_json(client, f"/api/session/{sid_dlq}/continuity/incidents?limit=20")
        assert_true(continuity_incidents["ok"], "continuity incidents endpoint should succeed")
        assert_true("items" in continuity_incidents and "summary" in continuity_incidents, "continuity incidents endpoint should return items and summary")
        continuity_next = get_json(client, f"/api/session/{sid_dlq}/continuity/next?limit=5")
        assert_true(continuity_next["ok"], "continuity next endpoint should succeed")
        assert_true("items" in continuity_next and "summary" in continuity_next, "continuity next endpoint should return items and summary")
        continuity_autopilot = get_json(client, f"/api/session/{sid_dlq}/continuity/autopilot")
        assert_true(continuity_autopilot["ok"], "continuity autopilot endpoint should succeed")
        assert_true("autopilot" in continuity_autopilot and "enabled" in continuity_autopilot["autopilot"], "continuity autopilot endpoint should return state")
        continuity_autopilot_preview = get_json(client, f"/api/session/{sid_dlq}/continuity/autopilot/preview")
        assert_true(continuity_autopilot_preview["ok"], "continuity autopilot preview endpoint should succeed")
        assert_true("preview" in continuity_autopilot_preview and "reason" in continuity_autopilot_preview["preview"], "continuity autopilot preview endpoint should return reason")
        continuity_autopilot_metrics = get_json(client, f"/api/session/{sid_dlq}/continuity/autopilot/metrics?window_ms=3600000")
        assert_true(continuity_autopilot_metrics["ok"], "continuity autopilot metrics endpoint should succeed")
        assert_true("metrics" in continuity_autopilot_metrics and "recentCount" in continuity_autopilot_metrics["metrics"], "continuity autopilot metrics endpoint should return counters")
        continuity_autopilot_dry_run = get_json(client, f"/api/session/{sid_dlq}/continuity/autopilot/dry-run?force=true")
        assert_true(continuity_autopilot_dry_run["ok"], "continuity autopilot dry-run endpoint should succeed")
        assert_true("report" in continuity_autopilot_dry_run and "snapshot" in continuity_autopilot_dry_run, "continuity autopilot dry-run endpoint should return report and snapshot")
        continuity_autopilot_guardrails = get_json(client, f"/api/session/{sid_dlq}/continuity/autopilot/guardrails")
        assert_true(continuity_autopilot_guardrails["ok"], "continuity autopilot guardrails endpoint should succeed")
        assert_true("guardrails" in continuity_autopilot_guardrails and "ok" in continuity_autopilot_guardrails["guardrails"], "continuity autopilot guardrails endpoint should return state")
        continuity_autopilot_mode_reco = get_json(client, f"/api/session/{sid_dlq}/continuity/autopilot/mode-recommendation")
        assert_true(continuity_autopilot_mode_reco["ok"], "continuity autopilot mode recommendation endpoint should succeed")
        assert_true("recommendedMode" in continuity_autopilot_mode_reco, "continuity autopilot mode recommendation endpoint should return recommended mode")
        continuity_autopilot_mode_drift = get_json(client, f"/api/session/{sid_dlq}/continuity/autopilot/mode-drift")
        assert_true(continuity_autopilot_mode_drift["ok"], "continuity autopilot mode drift endpoint should succeed")
        assert_true("drifted" in continuity_autopilot_mode_drift, "continuity autopilot mode drift endpoint should return drift status")
        continuity_autopilot_mode_alignment = get_json(client, f"/api/session/{sid_dlq}/continuity/autopilot/mode-alignment?limit=20")
