        root_task = next((e for e in entities_chain if str(e.get("kind", "")).lower() == "task" and str(e.get("title", "")) == "root"), None)
        mid_task = next((e for e in entities_chain if str(e.get("kind", "")).lower() == "task" and str(e.get("title", "")) == "middle"), None)
        leaf_task = next((e for e in entities_chain if str(e.get("kind", "")).lower() == "task" and str(e.get("title", "")) == "leaf"), None)
