        chain_items = relation_block.get("items", []) if relation_block else []
        assert_true(any("chain depth: 2" in str(item).lower() for item in chain_items), "dependency chain query should report transitive depth")
        query_blockers = post_json(client, "/api/turn", {"sessionId": sid_chain, "intent": f"show blockers for task {root_sel}"})
